mapper.select:
select a.id, u.real_name, a.attendance_date, a.check_in_time, a.check_out_time, a.status, a.late_minutes, a.early_minutes, a.work_hours, a.source, a.remark from attendance a left join user u on a.user_id = u.id
and u.real_name like concat('%',#{attendancePageDTO.realname},'%')
and a.attendance_date = #{attendancePageDTO.attendanceDate}
and a.status = #{attendancePageDTO.status}
and a.source = #{attendancePageDTO.source}
